"use client";

// ご旅行プラン（旅程）画面 — 東京→ホノルル 3泊5日。
// モバイルファースト(375px) の B2C 旅程管理画面。
//
// @gunjo/ui の使用状況:
//   PageHeader  … モバイル app-bar（戻る＋タイトル＋共有/追加アクション）
//   StatGroup   … 概要の主要数値（泊数 / 人数 / 予約番号）
//   Card        … 概要ヒーロー
//   Timeline    … 日程別の複合タイムライン（便/ホテル/アクティビティ混在）
//   Drawer      … 各予約の詳細（下から）
//   Badge / Button / Separator / Icon / MetadataList / CopyButton … 各所
//
// hand-roll したのは (1) 日付ヘッダー付き複合タイムラインの「行」見た目、
// (2) フライトの 出発→到着 区間ブロック(ItemDetail内)、(3) 共有/保存のアクションバー。
// 詳細はレポート参照。

import * as React from "react";
import {
  IconShare2,
  IconCirclePlus,
  IconDownload,
  IconChevronRight,
  IconClock,
  IconArrowRight,
} from "@tabler/icons-react";
import {
  PageHeader,
  StatGroup,
  Card,
  Badge,
  Button,
  Separator,
  Timeline,
  TimelineItem,
  TimelineTitle,
  TimelineDescription,
  TimelineTime,
  Drawer,
  DrawerContent,
  DrawerHeader,
  DrawerTitle,
  DrawerDescription,
  DrawerClose,
} from "@gunjo/ui";
import { TRIP } from "./trip-data";
import type { ItineraryItem, TripDay } from "./trip-data";
import { KIND_META } from "./item-meta";
import { ItemDetailBody } from "./ItemDetail";

/** タイムラインのマーカー — 種別アイコンを丸い色付きチップで。 */
function ItemMarker({ item }: { item: ItineraryItem }) {
  const meta = KIND_META[item.kind];
  return (
    <span
      className={`flex size-7 items-center justify-center rounded-full ${meta.markerClass}`}
      aria-hidden="true"
    >
      <meta.Glyph className="size-4" />
    </span>
  );
}

/** 1アイテム = タップ可能な Timeline 行。 */
function ItineraryRow({
  item,
  isLast,
  onSelect,
}: {
  item: ItineraryItem;
  isLast: boolean;
  onSelect: (item: ItineraryItem) => void;
}) {
  const meta = KIND_META[item.kind];
  return (
    <TimelineItem connector={!isLast} marker={<ItemMarker item={item} />}>
      <button
        type="button"
        onClick={() => onSelect(item)}
        className="-mx-2 flex w-[calc(100%+1rem)] items-center gap-2 rounded-lg px-2 py-1.5 text-left transition-colors hover:bg-accent focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring"
        aria-label={`${item.title} の詳細を開く`}
      >
        <span className="min-w-0 flex-1">
          {item.time ? (
            <TimelineTime className="flex items-center gap-1 tabular-nums">
              <IconClock className="size-3" aria-hidden="true" />
              {item.time}
            </TimelineTime>
          ) : (
            <TimelineTime className="text-muted-foreground/70">終日</TimelineTime>
          )}
          <TimelineTitle className="mt-0.5 flex flex-wrap items-center gap-x-2 gap-y-1">
            <span className="break-words">{item.title}</span>
            {item.kind === "flight" ? (
              <Badge variant={item.leg === "outbound" ? "info" : "secondary"}>
                {item.leg === "outbound" ? "往路" : "復路"}
              </Badge>
            ) : null}
          </TimelineTitle>
          {item.subtitle ? (
            <TimelineDescription className="mt-0.5">
              {item.subtitle}
            </TimelineDescription>
          ) : null}
          <span className="mt-1 inline-flex items-center text-[11px] text-muted-foreground">
            {meta.label}
          </span>
        </span>
        <IconChevronRight
          className="size-5 shrink-0 text-muted-foreground"
          aria-hidden="true"
        />
      </button>
    </TimelineItem>
  );
}

/** 1日分（日付ヘッダー + その日のアイテムのタイムライン）。 */
function DaySection({
  day,
  onSelect,
}: {
  day: TripDay;
  onSelect: (item: ItineraryItem) => void;
}) {
  return (
    <section aria-labelledby={`day-${day.dayNo}`} className="scroll-mt-16">
      <div className="sticky top-14 z-10 -mx-4 flex items-baseline gap-3 border-b border-border bg-background/95 px-4 py-2 backdrop-blur">
        <span className="flex size-9 shrink-0 flex-col items-center justify-center rounded-md bg-foreground text-background">
          <span className="text-[9px] leading-none">DAY</span>
          <span className="text-sm font-bold leading-none tabular-nums">
            {day.dayNo}
          </span>
        </span>
        <div className="min-w-0">
          <h2 id={`day-${day.dayNo}`} className="text-sm font-semibold">
            {day.dayNo}日目
            <span className="ml-2 font-normal text-muted-foreground">
              {day.dateLabel}
            </span>
          </h2>
          <p className="truncate text-xs text-muted-foreground">{day.place}</p>
        </div>
      </div>

      <div className="px-4 pt-4">
        <Timeline>
          {day.items.map((item, i) => (
            <ItineraryRow
              key={item.id}
              item={item}
              isLast={i === day.items.length - 1}
              onSelect={onSelect}
            />
          ))}
        </Timeline>
      </div>
    </section>
  );
}

export default function TripItineraryPage() {
  const [selected, setSelected] = React.useState<ItineraryItem | null>(null);
  const open = selected !== null;

  const handleOpenChange = (next: boolean) => {
    if (!next) setSelected(null);
  };

  const selectedMeta = selected ? KIND_META[selected.kind] : null;

  return (
    <div className="mx-auto flex min-h-dvh w-full max-w-md flex-col bg-background pb-24">
      <PageHeader
        title="ご旅行プラン"
        subtitle={`${TRIP.routeLabel}・${TRIP.durationLabel}`}
        onBack={() => undefined}
        align="center"
        actions={
          <>
            <Button
              variant="ghost"
              size="icon"
              className="size-11"
              aria-label="旅程を共有"
            >
              <IconShare2 className="size-5" aria-hidden="true" />
            </Button>
            <Button
              variant="ghost"
              size="icon"
              className="size-11"
              aria-label="予定を追加"
            >
              <IconCirclePlus className="size-5" aria-hidden="true" />
            </Button>
          </>
        }
      />

      <main className="flex flex-1 flex-col gap-6">
        {/* 旅行の概要（ヒーロー） */}
        <Card className="mx-4 mt-4 overflow-hidden">
          <div className="bg-gradient-to-br from-info-strong to-foreground p-5 text-background">
            <p className="text-xs opacity-90">{TRIP.dateRangeLabel}</p>
            <h1 className="mt-1 flex items-center gap-2 text-xl font-bold">
              東京
              <IconArrowRight className="size-5" aria-hidden="true" />
              ホノルル
            </h1>
            <p className="mt-1 text-sm opacity-90">{TRIP.title}</p>
          </div>
          <div className="p-4">
            <StatGroup
              card={false}
              cols={{ base: 3 }}
              items={[
                { label: "期間", value: TRIP.durationLabel },
                { label: "人数", value: TRIP.travelers },
                { label: "予約番号", value: TRIP.bookingRef },
              ]}
            />
            <Separator className="my-3" />
            <p className="flex items-start gap-1.5 text-xs text-muted-foreground">
              <IconClock className="mt-0.5 size-3.5 shrink-0" aria-hidden="true" />
              {TRIP.tzNote}
            </p>
          </div>
        </Card>

        {/* 日程別の複合タイムライン */}
        <div className="flex flex-col gap-2">
          {TRIP.days.map((day) => (
            <DaySection key={day.dayNo} day={day} onSelect={setSelected} />
          ))}
        </div>
      </main>

      {/* 旅程の操作バー（共有 / 追加 / オフライン保存） */}
      <nav
        aria-label="旅程の操作"
        className="fixed inset-x-0 bottom-0 z-20 mx-auto flex w-full max-w-md items-center gap-2 border-t border-border bg-background/95 px-4 py-3 pb-[max(0.75rem,env(safe-area-inset-bottom))] backdrop-blur"
      >
        <Button variant="outline" className="flex-1" size="lg">
          <IconShare2 className="size-4" aria-hidden="true" />
          共有
        </Button>
        <Button variant="outline" className="flex-1" size="lg">
          <IconDownload className="size-4" aria-hidden="true" />
          オフライン保存
        </Button>
        <Button variant="primary" className="flex-1" size="lg">
          <IconCirclePlus className="size-4" aria-hidden="true" />
          追加
        </Button>
      </nav>

      {/* 各予約の詳細 */}
      <Drawer open={open} onOpenChange={handleOpenChange}>
        <DrawerContent side="bottom" className="max-h-[85dvh]">
          {selected ? (
            <>
              <DrawerHeader>
                <DrawerTitle className="flex items-center gap-2 text-left">
                  {selectedMeta ? (
                    <span
                      className={`flex size-7 items-center justify-center rounded-full ${selectedMeta.markerClass}`}
                      aria-hidden="true"
                    >
                      <selectedMeta.Glyph className="size-4" />
                    </span>
                  ) : null}
                  {selected.title}
                </DrawerTitle>
                <DrawerDescription className="text-left">
                  {selected.time ? `${selected.time}（現地時間）` : "終日の予定"}
                </DrawerDescription>
              </DrawerHeader>
              <div className="overflow-y-auto">
                <ItemDetailBody item={selected} />
              </div>
              <div className="p-4 pt-2">
                <DrawerClose asChild>
                  <Button variant="outline" className="w-full" size="lg">
                    閉じる
                  </Button>
                </DrawerClose>
              </div>
            </>
          ) : null}
        </DrawerContent>
      </Drawer>
    </div>
  );
}

// アイテム種別 → アイコン / ラベル / 配色 の対応。タイムラインのマーカーと
// 詳細パネルの両方で使う single source of truth。
import {
  IconPlane,
  IconBuildingArch,
  IconMapPin,
  IconCar,
  IconBeach,
  type IconProps as TablerIconProps,
} from "@tabler/icons-react";
import type { ItemKind } from "./trip-data";

type TablerIcon = (props: TablerIconProps) => React.ReactNode;

interface KindMeta {
  label: string;
  Glyph: TablerIcon;
  /** マーカー丸の配色 (Tailwind utility)。 */
  markerClass: string;
  /** Badge variant。 */
  badge: "default" | "secondary" | "info" | "success" | "warning";
}

export const KIND_META: Record<ItemKind, KindMeta> = {
  flight: {
    label: "フライト",
    Glyph: IconPlane,
    markerClass: "bg-info-strong text-info-strong-foreground",
    badge: "info",
  },
  hotel: {
    label: "ホテル",
    Glyph: IconBuildingArch,
    markerClass: "bg-success-strong text-success-strong-foreground",
    badge: "success",
  },
  activity: {
    label: "アクティビティ",
    Glyph: IconMapPin,
    markerClass: "bg-foreground text-background",
    badge: "default",
  },
  transfer: {
    label: "送迎・移動",
    Glyph: IconCar,
    markerClass: "bg-secondary text-secondary-foreground",
    badge: "secondary",
  },
  free: {
    label: "フリータイム",
    Glyph: IconBeach,
    markerClass: "bg-secondary text-secondary-foreground",
    badge: "secondary",
  },
};

"use client";

// 各予約の詳細 — タイムラインのアイテムをタップすると下から開く Drawer の中身。
// 構造化フィールドは @gunjo/ui の MetadataList、コピー導線は CopyButton。
// フライトの 出発→到着 ブロックだけ kit に該当物が無く hand-roll（後述）。
import * as React from "react";
import {
  IconPlaneDeparture,
  IconPlaneArrival,
  IconArrowRight,
  IconTicket,
} from "@tabler/icons-react";
import { Badge, Button, MetadataList, Separator, CopyButton } from "@gunjo/ui";
import type { MetadataListItem } from "@gunjo/ui";
import { KIND_META } from "./item-meta";
import type { ItineraryItem, FlightItem } from "./trip-data";

function RefValue({ value }: { value: string }) {
  return (
    <span className="inline-flex items-center gap-1">
      <span className="font-mono tabular-nums">{value}</span>
      <CopyButton value={value} size="sm" copyLabel={`${value} をコピー`} />
    </span>
  );
}

/** 往路/復路フライトの 出発→到着 ブロック。kit に区間表示の primitive が無いので hand-roll。 */
function FlightRoute({ flight }: { flight: FlightItem }) {
  return (
    <div className="rounded-lg border border-border bg-muted/30 p-4">
      <div className="grid grid-cols-[1fr_auto_1fr] items-center gap-2">
        <div className="min-w-0 text-center">
          <IconPlaneDeparture
            className="mx-auto mb-1 size-5 text-muted-foreground"
            aria-hidden="true"
          />
          <p className="text-2xl font-bold tabular-nums leading-none">
            {flight.dep.time}
          </p>
          <p className="mt-1 text-sm font-semibold">{flight.dep.code}</p>
          <p className="truncate text-xs text-muted-foreground">{flight.dep.name}</p>
          <p className="mt-0.5 text-[11px] text-muted-foreground">{flight.dep.tzLabel}</p>
        </div>

        <div className="flex flex-col items-center gap-1 px-1">
          <span className="text-[11px] text-muted-foreground">{flight.duration}</span>
          <IconArrowRight className="size-5 text-muted-foreground" aria-hidden="true" />
        </div>

        <div className="min-w-0 text-center">
          <IconPlaneArrival
            className="mx-auto mb-1 size-5 text-muted-foreground"
            aria-hidden="true"
          />
          <p className="text-2xl font-bold tabular-nums leading-none">
            {flight.arr.time}
            {flight.arr.nextDay ? (
              <span className="align-super text-xs font-semibold text-info-strong">
                {" "}
                +1
              </span>
            ) : null}
          </p>
          <p className="mt-1 text-sm font-semibold">{flight.arr.code}</p>
          <p className="truncate text-xs text-muted-foreground">{flight.arr.name}</p>
          <p className="mt-0.5 text-[11px] text-muted-foreground">{flight.arr.tzLabel}</p>
        </div>
      </div>
    </div>
  );
}

function buildItems(item: ItineraryItem): MetadataListItem[] {
  switch (item.kind) {
    case "flight":
      return [
        { label: "便名", value: item.flightNo },
        { label: "運航", value: item.carrier },
        { label: "区間", value: `${item.leg === "outbound" ? "往路" : "復路"}・${item.cabin}` },
        { label: "座席", value: item.seat },
        { label: "所要時間", value: item.duration },
        { label: "eチケット番号", value: <RefValue value={item.eTicketNo} /> },
        { label: "予約番号", value: <RefValue value={item.bookingRef} /> },
      ];
    case "hotel":
      return [
        { label: "施設名", value: item.hotelName },
        { label: "住所", value: item.address },
        { label: "部屋タイプ", value: item.roomType },
        { label: "泊数", value: `${item.nights}泊` },
        { label: "チェックイン", value: `${item.checkIn} 以降` },
        { label: "チェックアウト", value: `${item.checkOut} まで` },
        { label: "予約番号", value: <RefValue value={item.bookingRef} /> },
      ];
    default: {
      const rows: MetadataListItem[] = [];
      if (item.meetingPoint) rows.push({ label: "集合場所", value: item.meetingPoint });
      if (item.time) rows.push({ label: "時刻", value: `${item.time}（現地時間）` });
      if (item.duration) rows.push({ label: "所要", value: item.duration });
      if (item.bookingRef)
        rows.push({ label: "予約番号", value: <RefValue value={item.bookingRef} /> });
      return rows;
    }
  }
}

export function ItemDetailBody({ item }: { item: ItineraryItem }) {
  const meta = KIND_META[item.kind];
  const note =
    item.kind === "flight" || item.kind === "hotel" ? undefined : item.note;
  const rows = buildItems(item);

  return (
    <div className="flex flex-col gap-4 px-4 pb-2">
      <div className="flex items-center gap-2">
        <Badge variant={meta.badge} icon={<meta.Glyph />}>
          {meta.label}
        </Badge>
        {item.subtitle ? (
          <span className="text-sm text-muted-foreground">{item.subtitle}</span>
        ) : null}
      </div>

      {item.kind === "flight" ? <FlightRoute flight={item} /> : null}

      {rows.length > 0 ? <MetadataList items={rows} layout="horizontal" /> : null}

      {note ? (
        <p className="rounded-md bg-muted/40 p-3 text-sm text-muted-foreground">
          {note}
        </p>
      ) : null}

      {item.kind === "flight" ? (
        <>
          <Separator />
          <Button variant="primary" className="w-full" size="lg">
            <IconTicket className="size-4" aria-hidden="true" />
            eチケットを表示
          </Button>
        </>
      ) : null}
    </div>
  );
}

// 旅程データ — 東京(HND) → ホノルル(HNL) 3泊5日。
// 実在する便名 (NH/JL)・ホテル・スポット・believable な時刻で構成した、
// ご旅行プラン画面のサンプルデータ。

export type ItemKind = "flight" | "hotel" | "activity" | "transfer" | "free";

/** 各旅程アイテムの基底。time は現地時間の "HH:MM"。 */
interface ItineraryBase {
  id: string;
  kind: ItemKind;
  /** タイムライン左に出す現地時刻。"HH:MM"。終日項目は省略可。 */
  time?: string;
  /** カード見出し。 */
  title: string;
  /** 見出し下の1行サマリー。 */
  subtitle?: string;
}

export interface FlightItem extends ItineraryBase {
  kind: "flight";
  /** 往路 / 復路。 */
  leg: "outbound" | "inbound";
  flightNo: string; // 例: NH184
  carrier: string; // 全日本空輸 等
  dep: { code: string; name: string; time: string; tzLabel: string };
  arr: { code: string; name: string; time: string; tzLabel: string; nextDay?: boolean };
  /** 所要 "Hh MMm" 表記。 */
  duration: string;
  seat: string;
  cabin: string;
  eTicketNo: string;
  bookingRef: string;
}

export interface HotelItem extends ItineraryBase {
  kind: "hotel";
  /** "checkin" は到着日に、"checkout" は出発日に置く。 */
  phase: "checkin" | "checkout";
  hotelName: string;
  address: string;
  nights: number;
  checkIn: string; // "15:00"
  checkOut: string; // "11:00"
  bookingRef: string;
  roomType: string;
}

export interface ActivityItem extends ItineraryBase {
  kind: "activity" | "transfer" | "free";
  /** 集合場所 / 出発地。 */
  meetingPoint?: string;
  /** 所要 "約2時間" など。 */
  duration?: string;
  /** 予約番号があれば。 */
  bookingRef?: string;
  note?: string;
}

export type ItineraryItem = FlightItem | HotelItem | ActivityItem;

export interface TripDay {
  /** 1日目, 2日目 … */
  dayNo: number;
  /** "6/14 (土)" 表記。 */
  dateLabel: string;
  /** 現地の概況 (場所)。 */
  place: string;
  items: ItineraryItem[];
}

export interface Trip {
  title: string;
  routeLabel: string; // 東京 → ホノルル
  durationLabel: string; // 3泊5日
  dateRangeLabel: string; // 2026/6/14 → 6/18
  travelers: string; // 大人2名
  bookingRef: string; // 予約番号(全体)
  tzNote: string; // 時差
  days: TripDay[];
}

